import React, { useState } from 'react';
import { motion } from 'framer-motion';
import {
  AlertTriangleIcon,
  ClockIcon,
  ShieldIcon,
  CheckCircleIcon,
  ChevronDownIcon,
  ChevronUpIcon
} from 'lucide-react';
import { StatusBadge } from '../components/StatusBadge';

const INITIAL_DISPUTES = [
  {
    id: 'DISP-401',
    requestRef: 'REQ-1042',
    student: 'Alex Rivera',
    volunteer: 'Jordan Lee',
    reason: 'Session was cut short by 20 minutes without prior notice. Volunteer left abruptly.',
    status: 'open',
    date: 'Oct 24, 2023'
  },
  {
    id: 'DISP-402',
    requestRef: 'REQ-0988',
    student: 'Sam Taylor',
    volunteer: 'David Kim',
    reason: 'Tutor did not show up to the scheduled meeting link after 15 minutes of waiting.',
    status: 'under-review',
    date: 'Oct 23, 2023'
  },
  {
    id: 'DISP-403',
    requestRef: 'REQ-0950',
    student: 'Elena Rodriguez',
    volunteer: 'Sarah Chen',
    reason: 'Disagreement over the material covered. Tutor was unprepared for the specific topics requested.',
    status: 'resolved',
    date: 'Oct 20, 2023'
  },
  {
    id: 'DISP-404',
    requestRef: 'REQ-0912',
    student: 'Marcus Johnson',
    volunteer: 'James Wilson',
    reason: 'Inappropriate language used during the session.',
    status: 'open',
    date: 'Oct 25, 2023'
  }
];

export function AdminDashboard() {
  const [disputes, setDisputes] = useState(INITIAL_DISPUTES);
  const [expandedId, setExpandedId] = useState(null);

  const handleResolve = (id) => {
    setDisputes(disputes.map((d) => (d.id === id ? { ...d, status: 'resolved' } : d)));
    setExpandedId(null);
  };

  const handleSuspend = (id, volunteerName) => {
    if (window.confirm(`Are you sure you want to suspend the account for ${volunteerName}?`)) {
      setDisputes(disputes.map((d) => (d.id === id ? { ...d, status: 'resolved' } : d)));
      setExpandedId(null);
      alert(`Account for ${volunteerName} has been suspended.`);
    }
  };

  const toggleExpand = (id) => {
    setExpandedId(expandedId === id ? null : id);
  };

  const activeDisputesCount = disputes.filter((d) => d.status === 'open' || d.status === 'under-review').length;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-8">
        <h1 className="text-2xl md:text-3xl font-bold text-gray-900">Dispute Resolution Center</h1>
        <p className="text-gray-500 mt-1">Manage platform conflicts and enforce community guidelines.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm flex items-center">
          <div className="p-4 rounded-full bg-red-50 text-red-600 mr-5">
            <AlertTriangleIcon className="w-8 h-8" />
          </div>
          <div>
            <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">Total Active Disputes</p>
            <p className="text-3xl font-bold text-gray-900 mt-1">{activeDisputesCount}</p>
          </div>
        </div>

        <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm flex items-center">
          <div className="p-4 rounded-full bg-indigo-50 text-indigo-600 mr-5">
            <ClockIcon className="w-8 h-8" />
          </div>
          <div>
            <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">Avg Resolution Time</p>
            <p className="text-3xl font-bold text-gray-900 mt-1">
              2.4 <span className="text-lg text-gray-500 font-medium">days</span>
            </p>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
        <div className="px-6 py-5 border-b border-gray-200 bg-gray-50/50 flex justify-between items-center">
          <h2 className="text-lg font-semibold text-gray-900 flex items-center">
            <ShieldIcon className="w-5 h-5 mr-2 text-indigo-600" />
            Flagged Cases
          </h2>
        </div>

        <div className="divide-y divide-gray-200">
          {disputes.map((dispute) => (
            <div
              key={dispute.id}
              className={`transition-colors ${expandedId === dispute.id ? 'bg-indigo-50/30' : 'hover:bg-gray-50'}`}
            >
              <div
                className="px-6 py-4 cursor-pointer flex flex-col sm:flex-row sm:items-center justify-between gap-4"
                onClick={() => toggleExpand(dispute.id)}
              >
                <div className="flex-1">
                  <div className="flex items-center space-x-3 mb-1">
                    <span className="text-sm font-bold text-gray-900">{dispute.id}</span>
                    <span className="text-xs text-gray-500">Ref: {dispute.requestRef}</span>
                    <StatusBadge status={dispute.status} />
                  </div>
                  <div className="text-sm text-gray-600 flex items-center space-x-2">
                    <span className="font-medium text-gray-900">{dispute.student}</span>
                    <span className="text-gray-400">vs</span>
                    <span className="font-medium text-gray-900">{dispute.volunteer}</span>
                    <span className="text-gray-300 mx-2">•</span>
                    <span className="text-gray-500">{dispute.date}</span>
                  </div>
                </div>

                <div className="flex items-center justify-between sm:justify-end w-full sm:w-auto">
                  <p className="text-sm text-gray-500 truncate max-w-[200px] sm:max-w-[150px] md:max-w-[250px] mr-4">
                    {expandedId === dispute.id ? '' : dispute.reason}
                  </p>
                  <button className="text-gray-400 hover:text-gray-600 focus:outline-none">
                    {expandedId === dispute.id ? <ChevronUpIcon className="w-5 h-5" /> : <ChevronDownIcon className="w-5 h-5" />}
                  </button>
                </div>
              </div>

              <motion.div
                initial={false}
                animate={{ height: expandedId === dispute.id ? 'auto' : 0, opacity: expandedId === dispute.id ? 1 : 0 }}
                className="overflow-hidden"
              >
                <div className="px-6 pb-6 pt-2 border-t border-gray-100">
                  <div className="bg-white border border-gray-200 rounded-lg p-4 mb-4 shadow-sm">
                    <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Dispute Reason</h4>
                    <p className="text-sm text-gray-800 leading-relaxed">{dispute.reason}</p>
                  </div>

                  {dispute.status !== 'resolved' && (
                    <div className="flex flex-wrap gap-3 justify-end">
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleSuspend(dispute.id, dispute.volunteer);
                        }}
                        className="px-4 py-2 bg-red-600 hover:bg-red-700 text-white text-sm font-medium rounded-md shadow-sm transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500"
                      >
                        Suspend Account
                      </button>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleResolve(dispute.id);
                        }}
                        className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-medium rounded-md shadow-sm transition-colors flex items-center focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
                      >
                        <CheckCircleIcon className="w-4 h-4 mr-1.5" />
                        Resolve Dispute
                      </button>
                    </div>
                  )}

                  {dispute.status === 'resolved' && (
                    <div className="flex justify-end">
                      <span className="inline-flex items-center text-sm font-medium text-green-600 bg-green-50 px-3 py-1.5 rounded-md border border-green-100">
                        <CheckCircleIcon className="w-4 h-4 mr-1.5" /> Case Closed
                      </span>
                    </div>
                  )}
                </div>
              </motion.div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
